import{_ as o,c as a,o as s,ag as i}from"./chunks/framework.DD2hp6gW.js";const l="/assets/settings-global-enable-discount.C7esmfx-.png",n="/assets/settings-global-bulk-table-position.BEAEwtN6.png",r="/assets/settings-global-discount-bar-position.DuMzgMLk.png",d="/assets/settings-global-calculate-from.C0KR2Ilw.png",e="/assets/settings-global-debug-checkbox.Cd_KV13w.png",g="/assets/settings-global-log-viewer.Co7I8obc.png",_=JSON.parse('{"title":"Global Settings","description":"","frontmatter":{},"headers":[],"relativePath":"settings/global-settings.md","filePath":"settings/global-settings.md","lastUpdated":1769871666000}'),c={name:"settings/global-settings.md"};function u(p,t,b,h,m,f){return s(),a("div",null,t[0]||(t[0]=[i('<h1 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h1><p>The <strong>Global Settings</strong> tab contains the main operational controls for the entire plugin, affecting how discounts are calculated and displayed across your store.</p><h2 id="global-options" tabindex="-1">Global Options <a class="header-anchor" href="#global-options" aria-label="Permalink to &quot;Global Options&quot;">​</a></h2><h3 id="enable-discount-add-on" tabindex="-1">Enable Discount Add-on <a class="header-anchor" href="#enable-discount-add-on" aria-label="Permalink to &quot;Enable Discount Add-on&quot;">​</a></h3><p><img src="'+l+'" alt="Enable Discount Add-on"></p><p>This is the master &quot;on/off&quot; switch for CampaignBay.</p><ul><li><strong>ON (Green):</strong> The plugin is active and will apply discounts to your store.</li><li><strong>OFF (Grey):</strong> The entire pricing engine is disabled. No discounts will be calculated or applied. This is a quick way to temporarily pause all campaigns.</li></ul><h3 id="bulk-table-position" tabindex="-1">Bulk Table Position <a class="header-anchor" href="#bulk-table-position" aria-label="Permalink to &quot;Bulk Table Position&quot;">​</a></h3><p><img src="'+n+'" alt="Bulk Table Position"></p><p>Controls where the &quot;Quantity Discount&quot; pricing table appears on product pages.</p><table tabindex="0"><thead><tr><th>Option</th><th>Placement</th></tr></thead><tbody><tr><td><strong>Below Cart</strong></td><td>Directly below the &quot;Add to Cart&quot; button</td></tr><tr><td><strong>Above Cart</strong></td><td>Directly above the &quot;Add to Cart&quot; button</td></tr><tr><td><strong>Below Meta</strong></td><td>Below product metadata (SKU, Category)</td></tr><tr><td><strong>Above Meta</strong></td><td>Above product metadata</td></tr></tbody></table><h3 id="discount-bar-position" tabindex="-1">Discount Bar Position <a class="header-anchor" href="#discount-bar-position" aria-label="Permalink to &quot;Discount Bar Position&quot;">​</a></h3><p><img src="'+r+'" alt="Discount Bar Position"></p><p>Controls where promotional bars (for Scheduled or BOGO discounts) appear on product pages.</p><table tabindex="0"><thead><tr><th>Option</th><th>Placement</th></tr></thead><tbody><tr><td><strong>Below Cart</strong></td><td>Below the &quot;Add to Cart&quot; section</td></tr><tr><td><strong>Above Cart</strong></td><td>Above the &quot;Add to Cart&quot; section</td></tr><tr><td><strong>Below Meta</strong></td><td>Below the product metadata</td></tr><tr><td><strong>Above Meta</strong></td><td>Above the product metadata</td></tr></tbody></table><h3 id="calculate-discount-from" tabindex="-1">Calculate Discount From <a class="header-anchor" href="#calculate-discount-from" aria-label="Permalink to &quot;Calculate Discount From&quot;">​</a></h3><p><img src="'+d+'" alt="Calculate Discount From"></p><p>Determines which price is used as the base for discount calculations.</p><ul><li><strong>Regular Price:</strong> Always calculates from the product&#39;s original price, ignoring any existing WooCommerce sales.</li><li><strong>Sale Price:</strong> If a product is already on sale in WooCommerce, the discount is calculated from that reduced price (prevents deep stacking).</li></ul><h2 id="debugging-logging" tabindex="-1">Debugging &amp; Logging <a class="header-anchor" href="#debugging-logging" aria-label="Permalink to &quot;Debugging &amp; Logging&quot;">​</a></h2><h3 id="enable-debug-mode" tabindex="-1">Enable Debug Mode <a class="header-anchor" href="#enable-debug-mode" aria-label="Permalink to &quot;Enable Debug Mode&quot;">​</a></h3><p><img src="'+e+'" alt="Enable Debug Mode"></p><p>When checked, the plugin logs detailed process information for troubleshooting.</p><p><img src="'+e+'" alt="Debug Mode Enabled"></p><p>Once enabled, two action buttons appear:</p><ul><li><strong>View Logs:</strong> Opens the Debug Log Viewer modal.</li><li><strong>Clear Log Files:</strong> Purges all current log history.</li></ul><h3 id="debug-log-viewer" tabindex="-1">Debug Log Viewer <a class="header-anchor" href="#debug-log-viewer" aria-label="Permalink to &quot;Debug Log Viewer&quot;">​</a></h3><p><img src="'+g+'" alt="Debug Log Viewer"></p><p>The log viewer provides:</p><ul><li><strong>Select Log Date:</strong> Choose which day&#39;s logs to view.</li><li><strong>Refresh:</strong> Reload the current log file.</li><li><strong>Download:</strong> Save the log file locally for sharing with support.</li><li><strong>Clear Log Files:</strong> Permanently delete all log entries.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Enable Debug Mode when diagnosing issues. Remember to disable it in production to avoid performance overhead.</p></div><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>Continue exploring the settings for products and messaging.</p><ul><li><strong><a href="./product-settings.html">Product Settings →</a></strong></li></ul>',35)]))}const q=o(c,[["render",u]]);export{_ as __pageData,q as default};
